import sqlite3
from sqlite3 import Error
import sys

def create_connection():
    conn = None
    try:
        conn = sqlite3.connect('phone_directory.db')
        return conn
    except Error as e:
        print(f"Error connecting to database: {e}")
        sys.exit(1)

def create_table(conn):
    try:
        cursor = conn.cursor()
        cursor.execute('''
            CREATE TABLE IF NOT EXISTS contacts (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                name TEXT NOT NULL,
                phone TEXT NOT NULL,
                email TEXT
            )
        ''')
        conn.commit()
    except Error as e:
        print(f"Error creating table: {e}")
        sys.exit(1)

def add_contact(conn, name, phone, email=None):
    try:
        cursor = conn.cursor()
        cursor.execute('INSERT INTO contacts (name, phone, email) VALUES (?, ?, ?)', (name, phone, email))
        conn.commit()
        print("Contact added successfully.")
    except Error as e:
        print(f"Error adding contact: {e}")

def get_contact(conn, name):
    try:
        cursor = conn.cursor()
        cursor.execute('SELECT * FROM contacts WHERE name = ?', (name,))
        contact = cursor.fetchone()
        if contact:
            print(f"ID: {contact[0]}, Name: {contact[1]}, Phone: {contact[2]}, Email: {contact[3]}")
        else:
            print("Contact not found.")
    except Error as e:
        print(f"Error retrieving contact: {e}")

def update_contact(conn, name, phone=None, email=None):
    try:
        cursor = conn.cursor()
        if phone and email:
            cursor.execute('UPDATE contacts SET phone = ?, email = ? WHERE name = ?', (phone, email, name))
        elif phone:
            cursor.execute('UPDATE contacts SET phone = ? WHERE name = ?', (phone, name))
        elif email:
            cursor.execute('UPDATE contacts SET email = ? WHERE name = ?', (email, name))
        conn.commit()
        print("Contact updated successfully.")
    except Error as e:
        print(f"Error updating contact: {e}")

def delete_contact(conn, name):
    try:
        cursor = conn.cursor()
        cursor.execute('DELETE FROM contacts WHERE name = ?', (name,))
        conn.commit()
        print("Contact deleted successfully.")
    except Error as e:
        print(f"Error deleting contact: {e}")

def list_contacts(conn):
    try:
        cursor = conn.cursor()
        cursor.execute('SELECT * FROM contacts ORDER BY name ASC')
        contacts = cursor.fetchall()
        if contacts:
            for contact in contacts:
                print(f"ID: {contact[0]}, Name: {contact[1]}, Phone: {contact[2]}, Email: {contact[3]}")
        else:
            print("No contacts found.")
    except Error as e:
        print(f"Error listing contacts: {e}")

def search_contact(conn, name):
    try:
        cursor = conn.cursor()
        cursor.execute('SELECT * FROM contacts WHERE name LIKE ?', (f'%{name}%',))
        contacts = cursor.fetchall()
        if contacts:
            for contact in contacts:
                print(f"ID: {contact[0]}, Name: {contact[1]}, Phone: {contact[2]}, Email: {contact[3]}")
        else:
            print("No matching contacts found.")
    except Error as e:
        print(f"Error searching contacts: {e}")

def main():
    conn = create_connection()
    create_table(conn)

    while True:
        print("\nPhone Directory CLI")
        print("1. Add Contact")
        print("2. Retrieve Contact")
        print("3. Update Contact")
        print("4. Delete Contact")
        print("5. List All Contacts")
        print("6. Search Contact")
        print("7. Exit")

        choice = input("Enter your choice: ")

        if choice == '1':
            name = input("Enter name: ")
            phone = input("Enter phone: ")
            email = input("Enter email (optional): ")
            add_contact(conn, name, phone, email if email else None)
        elif choice == '2':
            name = input("Enter name: ")
            get_contact(conn, name)
        elif choice == '3':
            name = input("Enter name: ")
            phone = input("Enter new phone (leave blank to skip): ")
            email = input("Enter new email (leave blank to skip): ")
            update_contact(conn, name, phone if phone else None, email if email else None)
        elif choice == '4':
            name = input("Enter name: ")
            delete_contact(conn, name)
        elif choice == '5':
            list_contacts(conn)
        elif choice == '6':
            name = input("Enter name to search: ")
            search_contact(conn, name)
        elif choice == '7':
            conn.close()
            print("Exiting...")
            break
        else:
            print("Invalid choice. Please try again.")

if __name__ == '__main__':
    main()
