from flask import Flask, request, jsonify
from flask_sqlalchemy import SQLAlchemy
from flask_jwt_extended import JWTManager, jwt_required, get_jwt_identity
from flask_limiter import Limiter
from flask_limiter.util import get_remote_address
from marshmallow import Schema, fields, validate, ValidationError
import re
from sqlalchemy.exc import IntegrityError
from datetime import datetime

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'postgresql://user:password@localhost/dbname'
app.config['JWT_SECRET_KEY'] = 'your-secret-key'
app.config['SQLALCHEMY_TRACK_MODIFICATIONS'] = False

db = SQLAlchemy(app)
jwt = JWTManager(app)
limiter = Limiter(
    app,
    key_func=get_remote_address,
    default_limits=["5 per minute"]
)

# Models
class User(db.Model):
    __tablename__ = 'users'
    id = db.Column(db.Integer, primary_key=True)
    username = db.Column(db.String(30), unique=True, nullable=False)
    email = db.Column(db.String(120), unique=True, nullable=False)
    display_name = db.Column(db.String(30))
    bio = db.Column(db.String(160))
    created_at = db.Column(db.DateTime, default=datetime.utcnow)

# Schemas
class UserUpdateSchema(Schema):
    display_name = fields.String(validate=validate.Length(min=3, max=30), required=False)
    email = fields.String(validate=validate.Email(), required=False)
    bio = fields.String(validate=validate.Length(max=160), required=False)

# Helper function
def is_email_taken(email, current_user_id):
    return db.session.query(
        db.exists().where(User.email == email).where(User.id != current_user_id)
    ).scalar()

@app.route('/api/v1/users/me', methods=['PATCH'])
@jwt_required()
@limiter.limit("5 per minute")
def update_user_profile():
    current_user_id = get_jwt_identity()

    try:
        data = UserUpdateSchema().load(request.get_json())
    except ValidationError as err:
        return jsonify({"error": err.messages}), 400

    if not data:
        return jsonify({"error": "No valid fields provided"}), 400

    user = User.query.get(current_user_id)
    if not user:
        return jsonify({"error": "User not found"}), 404

    if 'email' in data:
        if is_email_taken(data['email'], current_user_id):
            return jsonify({"error": "Email already in use"}), 409

    try:
        for field in data:
            setattr(user, field, data[field])

        db.session.commit()
        return jsonify({
            "message": "Profile updated successfully",
            "user": {
                "display_name": user.display_name,
                "email": user.email,
                "bio": user.bio
            }
        }), 200
    except IntegrityError:
        db.session.rollback()
        return jsonify({"error": "Email already in use (race condition)"}), 409
    except Exception as e:
        db.session.rollback()
        return jsonify({"error": str(e)}), 500

if __name__ == '__main__':
    app.run(debug=True)
