              :events="calendarEvents"
              :event-color="getEventColor"
              event-text-color="white"
              @click:event="editTask"
              @mousedown:event="startDrag"
              @mousemove:event="moveDrag"
              @mouseup:event="endDrag"
              @mouseleave:event="endDrag"
            ></v-calendar>
