<script>
import { mapState, mapActions } from 'vuex'

export default {
  data() {
    return {
      currentTask: {
        id: null,
        title: '',
        description: '',
        priority: 'Medium',
        deadline: null
      },
      isEditing: false,
      calendarDate: new Date().toISOString().substr(0, 10),
      dragEvent: null,
      dragStart: null,
      priorityOptions: ['High', 'Medium', 'Low'],
      priorityColors: {
        High: 'red',
        Medium: 'orange',
        Low: 'green'
      }
    }
  },
  computed: {
    ...mapState(['tasks']),
    calendarEvents() {
      return this.tasks.map(task => ({
        id: task.id,
        name: task.title,
        start: task.deadline,
        end: task.deadline,
        color: this.priorityColors[task.priority],
        timed: false
      }))
    }
  },
  methods: {
    ...mapActions(['addTask', 'updateTask', 'deleteTask']),
    saveTask() {
      if (!this.currentTask.title || !this.currentTask.deadline) {
        return
      }

      if (this.isEditing) {
        this.updateTask(this.currentTask)
      } else {
        this.addTask(this.currentTask)
      }
      this.resetForm()
    },
    editTask({ event }) {
      const task = this.tasks.find(t => t.id === event.id)
      if (task) {
        this.currentTask = { ...task }
        this.isEditing = true
      }
    },
    resetForm() {
      this.currentTask = {
        id: null,
        title: '',
        description: '',
        priority: 'Medium',
        deadline: null
      }
      this.isEditing = false
    },
    getEventColor(event) {
      const task = this.tasks.find(t => t.id === event.id)
      return task ? this.priorityColors[task.priority] : 'blue'
    },
    startDrag({ event, timed }) {
      if (event && !timed) {
        this.dragEvent = event
        this.dragStart = event.start
      }
    },
    moveDrag(e) {
      if (!this.dragEvent || !this.dragStart) return

      const start = this.dragStart
      const end = e.date
      const days = Math.round(Math.abs(new Date(end) - new Date(start)) / 86400000)

      if (days >= 0) {
        this.dragEvent.start = end
        this.dragEvent.end = end
      }
    },
    endDrag() {
      if (this.dragEvent) {
        const task = this.tasks.find(t => t.id === this.dragEvent.id)
        if (task) {
          const updatedTask = {
            ...task,
            deadline: this.dragEvent.start
          }
          this.updateTask(updatedTask)
        }
        this.dragEvent = null
        this.dragStart = null
      }
    }
  }
}
</script>
