from django.db import models
from django.contrib.auth.models import User

class PronunciationHistory(models.Model):
    user = models.ForeignKey(User, on_delete=models.CASCADE)
    word = models.CharField(max_length=100)
    user_pronunciation = models.TextField()
    accuracy_score = models.FloatField()
    feedback = models.TextField()
    timestamp = models.DateTimeField(auto_now_add=True)

    class Meta:
        ordering = ['-timestamp']

    def __str__(self):
        return f"{self.user.username} - {self.word} ({self.accuracy_score}%)"

# views.py
from django.shortcuts import render, redirect
from django.contrib.auth.decorators import login_required
from django.http import JsonResponse
from .models import PronunciationHistory
import speech_recognition as sr
import difflib

@login_required
def pronunciation_assessment(request):
    if request.method == 'POST':
        word = request.POST.get('word', '').lower()
        recognizer = sr.Recognizer()

        try:
            with sr.Microphone() as source:
                audio = recognizer.listen(source, timeout=5)
                user_pronunciation = recognizer.recognize_google(audio).lower()

                accuracy = difflib.SequenceMatcher(
                    None, word, user_pronunciation
                ).ratio() * 100

                feedback = "Good job!" if accuracy > 80 else "Try again!"

                PronunciationHistory.objects.create(
                    user=request.user,
                    word=word,
                    user_pronunciation=user_pronunciation,
                    accuracy_score=accuracy,
                    feedback=feedback
                )

                return JsonResponse({
                    'success': True,
                    'word': word,
                    'pronunciation': user_pronunciation,
                    'accuracy': accuracy,
                    'feedback': feedback
                })

        except Exception as e:
            return JsonResponse({'success': False, 'error': str(e)})

    return render(request, 'assessment/pronunciation.html')

@login_required
def history(request):
    history = PronunciationHistory.objects.filter(user=request.user)
    return render(request, 'assessment/history.html', {'history': history})

