import pickle

class TrieNode:
    def __init__(self):
        self.children = {}
        self.is_end = False

class Trie:
    def __init__(self):
        self.root = TrieNode()

    def insert(self, word):
        node = self.root
        for char in word.lower():
            if char not in node.children:
                node.children[char] = TrieNode()
            node = node.children[char]
        node.is_end = True

    def search(self, prefix):
        node = self.root
        for char in prefix.lower():
            if char not in node.children:
                return []
            node = node.children[char]
        return self._dfs(node, prefix.lower())

    def _dfs(self, node, prefix):
        suggestions = []
        if node.is_end:
            suggestions.append(prefix)
        for char, child in node.children.items():
            suggestions.extend(self._dfs(child, prefix + char))
        return suggestions

    def serialize(self):
        return pickle.dumps(self.root)

    @staticmethod
    def deserialize(data):
        trie = Trie()
        trie.root = pickle.loads(data)
        return trie
