import redis
from datetime import datetime
from functools import wraps

app = Flask(__name__)
redis_client = redis.StrictRedis(host='localhost', port=6379, db=0)

# Mock device API URLs (replace with actual endpoints)
DEVICE_API_URLS = {
    'fitbit': 'https://api.fitbit.com/1/user/-/activities/date/{date}.json',
    'garmin': 'https://api.garmin.com/wellness-api/rest/dailySummary/{date}'
}

def cache_response(timeout=300):
    def decorator(f):
        @wraps(f)
        def wrapped(*args, **kwargs):
            cache_key = f"{request.path}{request.query_string.decode()}"
            cached_data = redis_client.get(cache_key)
            if cached_data:
                return jsonify(cached_data.decode())
            response = f(*args, **kwargs)
            redis_client.setex(cache_key, timeout, response.get_data(as_text=True))
            return response
        return wrapped
    return decorator

@app.route('/api/devices/data', methods=['GET'])
@cache_response()
def get_device_data():
    device_type = request.args.get('device_type')
    start_date = request.args.get('start_date')
    end_date = request.args.get('end_date')

    # Validate parameters
    if not device_type or not start_date or not end_date:
        return jsonify({'error': 'Missing required parameters'}), 400

    try:
        start = datetime.strptime(start_date, '%Y-%m-%d')
        end = datetime.strptime(end_date, '%Y-%m-%d')
        if start > end:
            return jsonify({'error': 'Invalid date range'}), 400
    except ValueError:
        return jsonify({'error': 'Invalid date format. Use YYYY-MM-DD'}), 400

    if device_type.lower() not in DEVICE_API_URLS:
        return jsonify({'error': 'Unsupported device type'}), 400

    # Fetch and aggregate data from device APIs
    aggregated_data = []
    current_date = start
    while current_date <= end:
        date_str = current_date.strftime('%Y-%m-%d')
        try:
            # In a real implementation, you would add proper authentication headers
            url = DEVICE_API_URLS[device_type.lower()].format(date=date_str)
            response = requests.get(url)
            if response.status_code == 200:
                aggregated_data.append(response.json())
            else:
                aggregated_data.append({'date': date_str, 'error': 'Data unavailable'})
        except requests.RequestException:
            aggregated_data.append({'date': date_str, 'error': 'API request failed'})
        current_date = current_date + timedelta(days=1)

    return jsonify({
        'device_type': device_type,
        'start_date': start_date,
        'end_date': end_date,
        'data': aggregated_data
    })

if __name__ == '__main__':
    app.run(debug=True)
