/**
 * Implements hook_file_validate().
 */
function custom_upload_validation_file_validate($file) {
  $errors = array();

  // Validate file type
  $allowed_extensions = array('jpg', 'jpeg', 'png', 'gif', 'pdf', 'doc', 'docx');
  $file_extension = strtolower(pathinfo($file->filename, PATHINFO_EXTENSION));

  if (!in_array($file_extension, $allowed_extensions)) {
    $errors[] = t('File type .@extension is not allowed. Allowed types: @allowed.', array(
      '@extension' => $file_extension,
      '@allowed' => implode(', ', $allowed_extensions),
    ));
  }

  // Validate file size (5MB max)
  $max_size = 5 * 1024 * 1024;
  if ($file->filesize > $max_size) {
    $errors[] = t('File size (@size) exceeds maximum allowed size of @max_size.', array(
      '@size' => format_size($file->filesize),
      '@max_size' => format_size($max_size),
    ));
  }

  // Scan for malware if ClamAV is available
  if (function_exists('clamav_scan_file')) {
    $scan_result = clamav_scan_file($file->uri);
    if ($scan_result !== CLAMAV_SCAN_OK) {
      $errors[] = t('File rejected: Malware detected (@result).', array(
        '@result' => clamav_get_message($scan_result),
      ));
    }
  }

  return $errors;
}

/**
 * Implements hook_requirements().
 */
function custom_upload_validation_requirements($phase) {
  $requirements = array();

  if ($phase == 'runtime') {
    if (!function_exists('clamav_scan_file')) {
      $requirements['custom_upload_validation_clamav'] = array(
        'title' => t('ClamAV Integration'),
        'value' => t('Not detected'),
        'severity' => REQUIREMENT_WARNING,
        'description' => t('ClamAV is not installed. Malware scanning will be disabled.'),
      );
    }
  }

  return $requirements;
}
