const Koa = require('koa');
const Router = require('@koa/router');
const bodyParser = require('koa-bodyparser');
const crypto = require('crypto');
const axios = require('axios');
const rateLimit = require('koa-ratelimit');
const { v4: uuidv4 } = require('uuid');

const app = new Koa();
const router = new Router();

// In-memory store for webhooks (replace with DB in production)
const webhooks = new Map();

// Middleware
app.use(bodyParser());
app.use(async (ctx, next) => {
  try {
    await next();
  } catch (err) {
    ctx.status = err.status || 500;
    ctx.body = { error: err.message };
    console.error(err);
  }
});

// Rate limiting
const db = new Map();
app.use(rateLimit({
  driver: 'memory',
  db: db,
  duration: 60000,
  errorMessage: 'Too many requests',
  id: (ctx) => ctx.ip,
  headers: {
    remaining: 'Rate-Limit-Remaining',
    reset: 'Rate-Limit-Reset',
    total: 'Rate-Limit-Total'
  },
  max: 100,
  disableHeader: false,
}));

// Helper to generate HMAC signature
function generateHMAC(secret, payload) {
  return crypto.createHmac('sha256', secret).update(JSON.stringify(payload)).digest('hex');
}

// Dispatch webhook
async function dispatchWebhook(webhook, event, payload) {
  try {
    const signature = generateHMAC(webhook.secret, payload);
    const response = await axios.post(webhook.url, payload, {
      headers: {
        'X-Event-Type': event,
        'X-Signature': signature,
        'Content-Type': 'application/json'
      }
    });
    console.log(`Webhook dispatched to ${webhook.url} for event ${event}. Status: ${response.status}`);
  } catch (error) {
    console.error(`Failed to dispatch webhook to ${webhook.url}:`, error.message);
  }
}

// CRUD routes for webhooks
router.post('/webhooks', async (ctx) => {
  const { url, events, secret } = ctx.request.body;
  if (!url || !events || !secret) {
    ctx.throw(400, 'Missing required fields: url, events, secret');
  }

  const id = uuidv4();
  const webhook = { id, url, events, secret };
  webhooks.set(id, webhook);
  ctx.status = 201;
  ctx.body = webhook;
});

router.get('/webhooks/:id', async (ctx) => {
  const webhook = webhooks.get(ctx.params.id);
  if (!webhook) ctx.throw(404, 'Webhook not found');
  ctx.body = webhook;
});

router.put('/webhooks/:id', async (ctx) => {
  const webhook = webhooks.get(ctx.params.id);
  if (!webhook) ctx.throw(404, 'Webhook not found');

  const { url, events, secret } = ctx.request.body;
  if (!url || !events || !secret) {
    ctx.throw(400, 'Missing required fields: url, events, secret');
  }

  const updated = { ...webhook, url, events, secret };
  webhooks.set(ctx.params.id, updated);
  ctx.body = updated;
});

router.delete('/webhooks/:id', async (ctx) => {
  if (!webhooks.has(ctx.params.id)) ctx.throw(404, 'Webhook not found');
  webhooks.delete(ctx.params.id);
  ctx.status = 204;
});

// Event simulation endpoint (for testing)
router.post('/events/:type', async (ctx) => {
  const eventType = ctx.params.type;
  const payload = ctx.request.body;

  // Find all webhooks subscribed to this event
  for (const [_, webhook] of webhooks) {
    if (webhook.events.includes(eventType)) {
      await dispatchWebhook(webhook, eventType, payload);
    }
  }

  ctx.status = 200;
  ctx.body = { message: 'Event processed' };
});

app.use(router.routes()).use(router.allowedMethods());

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => console.log(`Server running on port ${PORT}`));
