import numpy as np
from dataclasses import dataclass
from typing import Dict, Any, Optional

@dataclass
class Experiment:
    """Core class for simulating a physical experiment."""
    setup_parameters: Dict[str, Any]
    results: Optional[Dict[str, Any]] = None

    def setup(self, **kwargs) -> None:
        """Set up the experiment with given parameters."""
        self.setup_parameters = kwargs
        self.results = None

    def run(self) -> None:
        """Run the experiment and compute results using numpy."""
        if 'initial_velocity' in self.setup_parameters and 'angle' in self.setup_parameters:
            angle_rad = np.radians(self.setup_parameters['angle'])
            v0 = self.setup_parameters['initial_velocity']
            g = 9.81  # gravity

            # Calculate time of flight and distance traveled (projectile motion)
            time_of_flight = (2 * v0 * np.sin(angle_rad)) / g
            distance = (v0 ** 2 * np.sin(2 * angle_rad)) / g

            self.results = {
                'time_of_flight': time_of_flight,
                'distance_traveled': distance
            }
        else:
            raise ValueError("Missing required setup parameters (initial_velocity, angle).")

    @staticmethod
    def compare_parameters(exp1: 'Experiment', exp2: 'Experiment') -> Dict[str, Any]:
        """Compare two experiments based on their setup parameters."""
        comparison = {}
        for key in set(exp1.setup_parameters.keys()).union(exp2.setup_parameters.keys()):
            val1 = exp1.setup_parameters.get(key, None)
            val2 = exp2.setup_parameters.get(key, None)
            comparison[key] = {'exp1': val1, 'exp2': val2}
        return comparison

    @staticmethod
    def compare_results(exp1: 'Experiment', exp2: 'Experiment') -> Dict[str, Any]:
        """Compare two experiments based on their results."""
        if exp1.results is None or exp2.results is None:
            raise ValueError("Both experiments must have results to compare.")
        comparison = {}
        for key in set(exp1.results.keys()).union(exp2.results.keys()):
            val1 = exp1.results.get(key, None)
            val2 = exp2.results.get(key, None)
            comparison[key] = {'exp1': val1, 'exp2': val2}
        return comparison
