import { Body, Controller, Post, Headers, HttpCode, HttpException, HttpStatus } from '@nestjs/common';
import { ApiTags, ApiHeader, ApiResponse, ApiBody } from '@nestjs/swagger';
import { PaymentsService } from './payments.service';
import { CreatePaymentDto } from './payment.dto';

@ApiTags('payments')
@Controller('payments')
export class PaymentsController {
  constructor(private readonly paymentsService: PaymentsService) {}

  @Post()
  @ApiHeader({ name: 'x-api-key', description: 'API key for authentication' })
  @ApiBody({ type: CreatePaymentDto })
  @ApiResponse({ status: 201, description: 'Payment created successfully' })
  @ApiResponse({ status: 400, description: 'Validation error' })
  @ApiResponse({ status: 401, description: 'Unauthorized' })
  @ApiResponse({ status: 502, description: 'Payment gateway error' })
  @HttpCode(201)
  async create(
    @Body() createPaymentDto: CreatePaymentDto,
    @Headers('x-api-key') apiKey: string,
  ) {
    if (!apiKey || apiKey !== process.env.API_KEY) {
      throw new HttpException('Unauthorized', HttpStatus.UNAUTHORIZED);
    }

    return this.paymentsService.processPayment(createPaymentDto);
  }
}

// payments.service.ts
import { Injectable, Logger } from '@nestjs/common';
import { InjectModel } from '@nestjs/mongoose';
import { Model } from 'mongoose';
import { Payment } from './payment.entity';
import { CreatePaymentDto } from './payment.dto';
import Stripe from 'stripe';

@Injectable()
export class PaymentsService {
  private readonly logger = new Logger(PaymentsService.name);
  private stripe: Stripe;

  constructor(
    @InjectModel(Payment.name) private paymentModel: Model<Payment>,
  ) {
    this.stripe = new Stripe(process.env.STRIPE_SECRET_KEY, {
      apiVersion: '2023-08-16',
    });
  }

  async processPayment(createPaymentDto: CreatePaymentDto) {
    const session = await this.paymentModel.db.startSession();
    session.startTransaction();

    try {
      const payment = new this.paymentModel({
        ...createPaymentDto,
        status: 'pending',
      });
      await payment.save({ session });

      const paymentIntent = await this.stripe.paymentIntents.create({
        amount: Math.round(createPaymentDto.amount * 100),
        currency: createPaymentDto.currency,
      });

      payment.stripePaymentIntentId = paymentIntent.id;
      payment.status = 'completed';
      await payment.save({ session });

      await session.commitTransaction();

      return {
        paymentId: payment._id,
        clientSecret: paymentIntent.client_secret,
      };
    } catch (error) {
      await session.abortTransaction();
      this.logger.error({
        message: 'Payment processing failed',
        error: error.message,
        details: error,
      });

      if (error instanceof Stripe.errors.StripeError) {
        throw new HttpException(
          {
            error: 'Payment gateway error',
            details: error.message,
          },
          HttpStatus.BAD_GATEWAY,
        );
      }

      throw error;
    } finally {
      session.endSession();
    }
  }
}

