from flask import Flask, request, jsonify
from pymongo import MongoClient
from werkzeug.security import generate_password_hash, check_password_hash
from functools import wraps
import os
from bson.objectid import ObjectId

app = Flask(__name__)

# MongoDB setup
client = MongoClient(os.getenv('MONGO_URI', 'mongodb://localhost:27017/'))
db = client['health_management']
patients_collection = db['patients']

# Predefined valid health conditions
VALID_CONDITIONS = ['diabetes', 'hypertension', 'asthma', 'arthritis', 'allergies']

# Security - Basic Auth (for demo, use proper auth in production)
def require_auth(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        auth = request.authorization
        if not auth or not check_auth(auth.username, auth.password):
            return jsonify({'error': 'Unauthorized'}), 401
        return f(*args, **kwargs)
    return decorated

def check_auth(username, password):
    # In production, use proper user database with hashed passwords
    users = {
        'admin': generate_password_hash('securepassword')
    }
    return username in users and check_password_hash(users[username], password)

@app.route('/patient/<string:patient_id>', methods=['PUT'])
@require_auth
def update_patient(patient_id):
    data = request.get_json()

    # Validate required fields
    if not all(key in data for key in ['name', 'age', 'conditions']):
        return jsonify({'error': 'Missing required fields'}), 400

    name = data['name']
    age = data['age']
    conditions = data['conditions']

    # Validate data types
    if not isinstance(name, str) or not isinstance(age, int) or not isinstance(conditions, list):
        return jsonify({'error': 'Invalid data types'}), 400

    # Validate age
    if age < 0:
        return jsonify({'error': 'Age must be non-negative'}), 400

    # Validate conditions
    if not all(isinstance(cond, str) and cond in VALID_CONDITIONS for cond in conditions):
        return jsonify({'error': 'Invalid health conditions'}), 400

    # Update patient in MongoDB
    try:
        result = patients_collection.update_one(
            {'_id': ObjectId(patient_id)},
            {'$set': {
                'name': name,
                'age': age,
                'conditions': conditions
            }}
        )

        if result.matched_count == 0:
            return jsonify({'error': 'Patient not found'}), 404

        # Return updated patient data
        updated_patient = patients_collection.find_one({'_id': ObjectId(patient_id)})
        updated_patient['_id'] = str(updated_patient['_id'])  # Convert ObjectId to string
        return jsonify(updated_patient), 200

    except Exception as e:
        return jsonify({'error': str(e)}), 400

if __name__ == '__main__':
    app.run(debug=True)
