# Define the game class to manage the adventure game
class CastleAdventureGame:
    def __init__(self):
        # Initialize game state with default values
        self.current_room = "entrance"
        self.inventory = []
        self.game_data = {
            "rooms": {
                "entrance": {
                    "description": "You are at the entrance of the castle. A large wooden door stands before you.",
                    "items": ["torch", "key"],
                    "actions": ["open door", "look around"]
                },
                "hallway": {
                    "description": "A long hallway with torches lining the walls. Doors lead to other rooms.",
                    "items": ["painting", "sword"],
                    "actions": ["go left", "go right", "go back"]
                },
                "treasure_room": {
                    "description": "A room filled with gold and jewels. A chest sits in the center.",
                    "items": ["chest", "crown"],
                    "actions": ["open chest", "leave room"]
                }
            },
            "saved_file": "save_game.json"
        }

    # Display the current room description and available actions
    def display_room(self):
        room = self.game_data["rooms"][self.current_room]
        print("\n" + room["description"])
        print("Items here:", ", ".join(room["items"]))
        print("Actions:", ", ".join(room["actions"]))

    # Handle player actions
    def handle_action(self, action):
        room = self.game_data["rooms"][self.current_room]

        if action == "look around":
            self.display_room()
        elif action == "open door" and self.current_room == "entrance":
            if "key" in self.inventory:
                self.current_room = "hallway"
                print("You unlocked and opened the door.")
            else:
                print("The door is locked. You need a key.")
        elif action == "go left" and self.current_room == "hallway":
            self.current_room = "treasure_room"
            print("You entered the treasure room.")
        elif action == "go right" and self.current_room == "hallway":
            print("You find a dead end.")
        elif action == "go back" and self.current_room == "hallway":
            self.current_room = "entrance"
            print("You returned to the entrance.")
        elif action == "open chest" and self.current_room == "treasure_room":
            print("You found the treasure! You win!")
            return False  # End game
        elif action == "leave room" and self.current_room == "treasure_room":
            self.current_room = "hallway"
            print("You left the treasure room.")
        elif action == "save":
            self.save_game()
            print("Game saved.")
        elif action == "quit":
            return False  # End game
        else:
            print("Invalid action. Try again.")

        return True  # Continue game

    # Save the current game state to a JSON file
    def save_game(self):
        save_data = {
            "current_room": self.current_room,
            "inventory": self.inventory
        }
        with open(self.game_data["saved_file"], "w") as file:
            json.dump(save_data, file)

    # Load a saved game state from a JSON file
    def load_game(self):
        if os.path.exists(self.game_data["saved_file"]):
            with open(self.game_data["saved_file"], "r") as file:
                save_data = json.load(file)
                self.current_room = save_data["current_room"]
                self.inventory = save_data["inventory"]
            print("Game loaded successfully.")
        else:
            print("No saved game found.")

    # Main game loop
    def play(self):
        print("Welcome to the Castle Adventure Game!")
        print("Type 'save' to save your progress or 'quit' to exit.")

        # Check for saved game
        if input("Load saved game? (yes/no): ").lower() == "yes":
            self.load_game()

        game_active = True
        while game_active:
            self.display_room()
            action = input("What would you like to do? ").lower()
            game_active = self.handle_action(action)

        print("Thanks for playing!")

# Start the game
if __name__ == "__main__":
    game = CastleAdventureGame()
    game.play()
