  const data = fs.readFileSync(BLOCKED_IPS_FILE, 'utf8');
  JSON.parse(data).forEach(ip => blockedIPs.add(ip));
}

// Log blocked IP to file
function logBlockedIP(ip) {
  blockedIPs.add(ip);
  fs.writeFileSync(BLOCKED_IPS_FILE, JSON.stringify([...blockedIPs]), 'utf8');
}

// Middleware to check blocked IPs
function ipBlocker(req, res, next) {
  if (blockedIPs.has(req.ip)) {
    return res.status(403).send('Access forbidden - IP blocked');
  }
  next();
}

// Admin interface to manage blocked IPs
