        this.kafkaTemplate = kafkaTemplate;
    }

    @Retryable(
        retryFor = { Exception.class },
        maxAttempts = 3,
        backoff = @Backoff(delay = 1000)
    )
    public void publish(String topic, FulfillmentEvent event) {
        kafkaTemplate.send(topic, event);
    }
