import io.swagger.v3.oas.annotations.*;
import io.swagger.v3.oas.annotations.responses.*;
import jakarta.validation.Valid;
import org.springframework.http.*;
import org.springframework.security.access.prepost.PreAuthorize;
import org.springframework.transaction.annotation.Transactional;
import org.springframework.web.bind.annotation.*;
import java.util.stream.Collectors;

@RestController
@RequestMapping("/fulfillments")
@OpenAPIDefinition(info = @Info(title = "Fulfillment API"))
public class FulfillmentController {
    private final FulfillmentRepository repository;
    private final KafkaPublisher kafkaPublisher;

    public FulfillmentController(FulfillmentRepository repository, KafkaPublisher kafkaPublisher) {
        this.repository = repository;
        this.kafkaPublisher = kafkaPublisher;
    }

    @Operation(summary = "Create a fulfillment request")
    @ApiResponses(value = {
        @ApiResponse(responseCode = "201", description = "Fulfillment created"),
        @ApiResponse(responseCode = "400", description = "Invalid input"),
        @ApiResponse(responseCode = "403", description = "Forbidden")
    })
    @PostMapping
    @Transactional
    @PreAuthorize("hasAuthority('SCOPE_fulfillment.write')")
    public ResponseEntity<Void> createFulfillment(@Valid @RequestBody FulfillmentRequest request) {
        Fulfillment fulfillment = new Fulfillment();
        fulfillment.setOrderId(request.getOrderId());
        fulfillment.setItems(request.getItems().stream()
            .map(item -> {
                Fulfillment.Item i = new Fulfillment.Item();
                i.setProductId(item.getProductId());
                i.setQuantity(item.getQuantity());
                return i;
            })
            .collect(Collectors.toList()));
        fulfillment.setWarehouseId(request.getWarehouseId());
        fulfillment.setRequestedShipDate(request.getRequestedShipDate());

        repository.save(fulfillment);

        FulfillmentEvent event = new FulfillmentEvent();
        event.setOrderId(fulfillment.getOrderId());
        event.setItems(fulfillment.getItems().stream()
            .map(item -> {
                FulfillmentEvent.Item i = new FulfillmentEvent.Item();
                i.setProductId(item.getProductId());
                i.setQuantity(item.getQuantity());
                return i;
            })
            .collect(Collectors.toList()));
        event.setWarehouseId(fulfillment.getWarehouseId());
        event.setRequestedShipDate(fulfillment.getRequestedShipDate());

        kafkaPublisher.publish("fulfillment.requested", event);

        return ResponseEntity.status(HttpStatus.CREATED).build();
    }
}

