using System;
using System.ComponentModel.DataAnnotations;
using System.Net;
using System.Net.Http;
using System.Text.Json;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Caching.Memory;
using Microsoft.Extensions.Logging;
using Polly;
using Polly.Retry;
using Swashbuckle.AspNetCore.Annotations;

namespace CurrencyConversionMicroservice.Controllers
{
    [ApiController]
    [Route("[controller]")]
    public class ConvertController : ControllerBase
    {
        private readonly IHttpClientFactory _httpClientFactory;
        private readonly IMemoryCache _cache;
        private readonly ILogger<ConvertController> _logger;
        private readonly AsyncRetryPolicy<HttpResponseMessage> _retryPolicy;
        private const string ApiKeyHeader = "X-Api-Key";
        private const string ValidApiKey = "your-api-key"; // Replace with secure storage

        public ConvertController(
            IHttpClientFactory httpClientFactory,
            IMemoryCache cache,
            ILogger<ConvertController> logger)
        {
            _httpClientFactory = httpClientFactory;
            _cache = cache;
            _logger = logger;

            _retryPolicy = Policy<HttpResponseMessage>
                .Handle<HttpRequestException>()
                .OrResult(x => !x.IsSuccessStatusCode)
                .WaitAndRetryAsync(3, retryAttempt => 
                    TimeSpan.FromSeconds(Math.Pow(2, retryAttempt)));
        }

        [HttpGet]
        [SwaggerOperation(
            Summary = "Convert currency amount",
            Description = "Converts an amount from one currency to another using real-time exchange rates."
        )]
        [SwaggerResponse(200, "Successful conversion", typeof(ConversionResponse))]
        [SwaggerResponse(400, "Invalid input", typeof(ValidationErrorResponse))]
        [SwaggerResponse(401, "Unauthorized - Missing or invalid API key")]
        [SwaggerResponse(503, "Rate service unavailable", typeof(ServiceUnavailableResponse))]
        public async Task<IActionResult> Convert(
            [FromQuery, Required] string fromCurrency,
            [FromQuery, Required] string toCurrency,
            [FromQuery, Required, Range(0.01, double.MaxValue)] decimal amount)
        {
            var correlationId = Guid.NewGuid().ToString();
            _logger.LogInformation(new { correlationId, fromCurrency, toCurrency, amount }, "Request received");

            if (!Request.Headers.TryGetValue(ApiKeyHeader, out var apiKey) || apiKey != ValidApiKey)
            {
                _logger.LogWarning(new { correlationId }, "Unauthorized request");
                return Unauthorized();
            }

            var cacheKey = $"{fromCurrency}_{toCurrency}";
            if (_cache.TryGetValue(cacheKey, out decimal exchangeRate))
            {
                _logger.LogInformation(new { correlationId, cacheKey }, "Cache hit");
                return Ok(CreateResponse(fromCurrency, toCurrency, amount, exchangeRate));
            }

            try
            {
                var client = _httpClientFactory.CreateClient("ExchangeRates");
                var response = await _retryPolicy.ExecuteAsync(() => 
                    client.GetAsync($"latest?base={fromCurrency}&symbols={toCurrency}"));

                if (!response.IsSuccessStatusCode)
                {
                    _logger.LogError(new { correlationId, statusCode = response.StatusCode }, "Rate service failure");
                    return StatusCode(503, new { error = "Rate service unavailable", details = response.ReasonPhrase });
                }

                var content = await response.Content.ReadAsStringAsync();
                var rates = JsonSerializer.Deserialize<ExchangeRatesResponse>(content);
                exchangeRate = rates.Rates[toCurrency];

                _cache.Set(cacheKey, exchangeRate, TimeSpan.FromMinutes(5));
                _logger.LogInformation(new { correlationId, cacheKey, exchangeRate }, "Cache updated");

                return Ok(CreateResponse(fromCurrency, toCurrency, amount, exchangeRate));
            }
            catch (Exception ex)
            {
                _logger.LogError(new { correlationId, exception = ex.ToString() }, "Unhandled exception");
                return StatusCode(503, new { error = "Rate service unavailable", details = ex.Message });
            }
        }

        private ConversionResponse CreateResponse(string from, string to, decimal amount, decimal rate)
        {
            return new ConversionResponse
            {
                FromCurrency = from,
                ToCurrency = to,
                ExchangeRate = rate,
                OriginalAmount = amount,
                ConvertedAmount = amount * rate,
                Timestamp = DateTime.UtcNow
            };
        }
    }

    public class ExchangeRatesResponse
    {
        public Dictionary<string, decimal> Rates { get; set; }
    }

    public class ConversionResponse
    {
        public string FromCurrency { get; set; }
        public string ToCurrency { get; set; }
        public decimal ExchangeRate { get; set; }
        public decimal OriginalAmount { get; set; }
        public decimal ConvertedAmount { get; set; }
        public DateTime Timestamp { get; set; }
    }

    public class ValidationErrorResponse
    {
        public Dictionary<string, string[]> Errors { get; set; }
    }

    public class ServiceUnavailableResponse
    {
        public string Error { get; set; }
        public string Details { get; set; }
    }
}

