Here's the Django view implementation for managing subscription preferences:

```python
from django.shortcuts import render, redirect
from django.views.decorators.http import require_http_methods
from django.views.decorators.csrf import csrf_protect
from django.contrib import messages
from django.utils import timezone
from .models import Subscription
from .forms import SubscriptionForm

@csrf_protect
@require_http_methods(["GET", "POST"])
def manage_subscription(request):
    if not request.user.is_authenticated:
        messages.error(request, "You must be logged in to manage subscriptions.")
        return redirect('login')

    if request.method == 'POST':
        form = SubscriptionForm(request.POST)
        if form.is_valid():
            subscription_status = form.cleaned_data['subscription_status']

            Subscription.objects.update_or_create(
                user_id=request.user.id,
                defaults={
                    'subscription_status': subscription_status,
                    'update_timestamp': timezone.now()
                }
            )

            action = "subscribed" if subscription_status else "unsubscribed"
            messages.success(request, f"You have successfully {action}.")
            return redirect('subscription_confirmation')
    else:
        try:
            subscription = Subscription.objects.get(user_id=request.user.id)
            initial_data = {'subscription_status': subscription.subscription_status}
            form = SubscriptionForm(initial=initial_data)
        except Subscription.DoesNotExist:
            form = SubscriptionForm()

    return render(request, 'subscription/manage.html', {'form': form})
