async function initializeDatabase() {
    const connection = await pool.getConnection();
    try {
        await connection.query(`
            CREATE TABLE IF NOT EXISTS users (
                userID INT AUTO_INCREMENT PRIMARY KEY,
                username VARCHAR(255) NOT NULL,
                email VARCHAR(255) NOT NULL UNIQUE
            )
        `);

        await connection.query(`
            CREATE TABLE IF NOT EXISTS products (
                productID INT AUTO_INCREMENT PRIMARY KEY,
                name VARCHAR(255) NOT NULL,
                price DECIMAL(10, 2) NOT NULL
            )
        `);

        await connection.query(`
            CREATE TABLE IF NOT EXISTS reviews (
                reviewID INT AUTO_INCREMENT PRIMARY KEY,
                userID INT NOT NULL,
                productID INT NOT NULL,
                rating TINYINT NOT NULL CHECK (rating BETWEEN 1 AND 5),
                comment TEXT,
                createdAt TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                FOREIGN KEY (userID) REFERENCES users(userID),
                FOREIGN KEY (productID) REFERENCES products(productID)
            )
        `);
    } finally {
        connection.release();
    }
}

initializeDatabase();

// API endpoint to post a new review
app.post('/api/reviews', 
    [
        body('userID').isInt().withMessage('User ID must be an integer'),
        body('productID').isInt().withMessage('Product ID must be an integer'),
        body('rating').isInt({ min: 1, max: 5 }).withMessage('Rating must be between 1 and 5'),
        body('comment').isString().isLength({ max: 1000 }).withMessage('Comment must be a string with max 1000 characters')
    ],
    async (req, res) => {
        const errors = validationResult(req);
        if (!errors.isEmpty()) {
            return res.status(400).json({ errors: errors.array() });
        }

        const { userID, productID, rating, comment } = req.body;

        try {
            const connection = await pool.getConnection();
            try {
                await connection.query(
                    'INSERT INTO reviews (userID, productID, rating, comment) VALUES (?, ?, ?, ?)',
                    [userID, productID, rating, comment]
                );
                res.status(201).json({ message: 'Review submitted successfully' });
            } finally {
                connection.release();
            }
        } catch (error) {
            console.error('Error submitting review:', error);
            res.status(500).json({ error: 'Failed to submit review' });
        }
    }
);

// API endpoint to fetch all reviews for a product
app.get('/api/products/:productID/reviews', async (req, res) => {
    const productID = req.params.productID;

    try {
        const connection = await pool.getConnection();
        try {
            const [reviews] = await connection.query(
                'SELECT * FROM reviews WHERE productID = ? ORDER BY createdAt DESC',
                [productID]
            );
            res.json(reviews);
        } finally {
            connection.release();
        }
