Here's the implementation:

```javascript
const express = require('express');
const axios = require('axios');
const jwt = require('jsonwebtoken');
const router = express.Router();

const SERVICE_URLS = {
  twitter: 'https://api.twitter.com/2/tweets',
  instagram: 'https://graph.instagram.com/me/media',
  blogs: 'https://api.example.com/blogs'
};

const verifyToken = (token) => {
  try {
    return jwt.verify(token, process.env.OAUTH_SECRET);
  } catch (err) {
    return null;
  }
};

const fetchContent = async (service, token) => {
  try {
    const response = await axios.get(SERVICE_URLS[service], {
      headers: { Authorization: `Bearer ${token}` }
    });
    return response.data;
  } catch (err) {
    console.error(`Error fetching ${service} content:`, err.message);
    return null;
  }
};

router.get('/content/feed', async (req, res) => {
  const authHeader = req.headers.authorization;
  if (!authHeader) return res.sendStatus(401);

  const token = authHeader.split(' ')[1];
  const decoded = verifyToken(token);
  if (!decoded) return res.sendStatus(401);

  try {
    const [twitterPosts, instagramPosts, blogPosts] = await Promise.all([
      fetchContent('twitter', token),
      fetchContent('instagram', token),
      fetchContent('blogs', token)
    ]);

    if (!twitterPosts && !instagramPosts && !blogPosts) {
      return res.status(503).json({ error: 'Content services unavailable' });
    }

    const combinedFeed = []
      .concat(
        twitterPosts?.data?.map(post => ({ ...post, source: 'twitter' })) || [],
        instagramPosts?.data?.map(post => ({ ...post, source: 'instagram' })) || [],
        blogPosts?.data?.map(post => ({ ...post, source: 'blogs' })) || []
      )
      .sort((a, b) => new Date(b.timestamp) - new Date(a.timestamp));

    if (combinedFeed.length === 0) return res.status(404).json({ error: 'No content found' });

    res.json(combinedFeed);
  } catch (err) {
    console.error('Error processing feed:', err);
    res.status(500).json({ error: 'Internal server error' });
  }
});

module.exports = router;
